// ============================================================
// FIXED VALIDATE NODE — v2
// Uses simple string manipulation instead of URL class
// Reads field keys exactly as n8n Form Trigger outputs them
// ============================================================

// n8n Form Trigger outputs fields using the fieldLabel value as key
const item = $input.first().json;

// --- Read form fields safely ---
const rawUrl   = (item.websiteUrl   || item['websiteUrl']   || '').toString().trim();
const name     = (item.yourName     || item['yourName']     || 'User').toString().trim();
const email    = (item.yourEmail    || item['yourEmail']    || '').toString().trim();
const niche    = (item.niche        || item['niche']        || 'Business & Services').toString().trim();
const strategy = (item.strategy     || item['strategy']     || 'Balanced').toString().trim();
const region   = (item.region       || item['region']       || 'Global').toString().trim();

// --- Guard: URL must not be empty ---
if (!rawUrl || rawUrl.length < 3) {
  throw new Error('Please provide a valid website URL.');
}

// --- Clean URL: add https:// if missing ---
let cleanUrl = rawUrl;
if (!cleanUrl.startsWith('http://') && !cleanUrl.startsWith('https://')) {
  cleanUrl = 'https://' + cleanUrl;
}
// Remove trailing slash
cleanUrl = cleanUrl.replace(/\/+$/, '');

// --- Extract domain using simple string split (no URL class needed) ---
// Strip protocol
let domain = cleanUrl.replace(/^https?:\/\//i, '');
// Strip path, query, hash
domain = domain.split('/')[0].split('?')[0].split('#')[0];
// Strip port
domain = domain.split(':')[0];
// Strip www.
domain = domain.replace(/^www\./i, '').toLowerCase();

// Guard: domain must contain a dot
if (!domain || domain.indexOf('.') === -1) {
  throw new Error('Invalid URL. Example: https://yourwebsite.com');
}

// Extract domain root (e.g. "myshop" from "myshop.com")
const domainParts = domain.split('.');
const domainRoot  = domainParts[0];
const tld         = domainParts[domainParts.length - 1];
const slug        = domainRoot.replace(/[^a-z0-9]/gi, ' ').trim();

// --- Strategy config ---
const strategyConfig = {
  'Aggressive': { minDA: 30, maxPlatforms: 80 },
  'Balanced':   { minDA: 50, maxPlatforms: 50 },
  'Safe':       { minDA: 70, maxPlatforms: 25 }
};
const config = strategyConfig[strategy] || strategyConfig['Balanced'];

// --- Niche color map ---
const nicheColors = {
  'Technology & Software':  '#6366f1',
  'E-commerce & Retail':    '#ec4899',
  'Health & Wellness':      '#10b981',
  'Finance & Investment':   '#f59e0b',
  'Education & E-Learning': '#3b82f6',
  'Travel & Tourism':       '#14b8a6',
  'Food & Restaurant':      '#f97316',
  'Real Estate':            '#8b5cf6',
  'Marketing & SEO':        '#ef4444',
  'Legal & Law':            '#64748b',
  'Gaming & Entertainment': '#a855f7',
  'News & Blog':            '#06b6d4',
  'Business & Services':    '#6366f1'
};
const nicheColor = nicheColors[niche] || '#6366f1';

// --- Auto-detect niche from domain if user selected default ---
const domainLower = (domain + ' ' + slug).toLowerCase();
const autoNicheMap = [
  { niche: 'Technology & Software',  keywords: ['tech','software','app','dev','code','digital','cloud','saas','api','ai','data','cyber','iot'] },
  { niche: 'E-commerce & Retail',    keywords: ['shop','store','buy','sell','mart','deal','product','retail','market','fashion','wear'] },
  { niche: 'Health & Wellness',      keywords: ['health','fitness','medical','clinic','care','doctor','nutrition','diet','yoga','gym','pharma','med'] },
  { niche: 'Finance & Investment',   keywords: ['finance','invest','bank','loan','credit','money','fund','stock','crypto','trade','forex'] },
  { niche: 'Education & E-Learning', keywords: ['learn','edu','course','school','academy','tutor','study','college','training','skill'] },
  { niche: 'Travel & Tourism',       keywords: ['travel','tour','trip','hotel','flight','vacation','holiday','visa','cruise','booking'] },
  { niche: 'Food & Restaurant',      keywords: ['food','recipe','restaurant','cafe','eat','meal','cook','kitchen','bakery','catering'] },
  { niche: 'Real Estate',            keywords: ['realty','estate','property','home','house','rent','apartment','land','mortgage'] },
  { niche: 'Marketing & SEO',        keywords: ['market','seo','brand','ads','content','media','growth','agency','promotion'] },
  { niche: 'Legal & Law',            keywords: ['law','legal','attorney','lawyer','firm','justice','court','advocate'] },
  { niche: 'Gaming & Entertainment', keywords: ['game','gaming','play','esport','sport','entertainment','movie','music','stream'] },
  { niche: 'News & Blog',            keywords: ['news','blog','post','article','journal','magazine','press','daily'] }
];

let detectedNiche = niche; // use what user selected
if (niche === 'Business & Services') {
  // Try to auto-detect from domain
  for (let i = 0; i < autoNicheMap.length; i++) {
    const entry = autoNicheMap[i];
    for (let j = 0; j < entry.keywords.length; j++) {
      if (domainLower.indexOf(entry.keywords[j]) !== -1) {
        detectedNiche = entry.niche;
        break;
      }
    }
    if (detectedNiche !== 'Business & Services') break;
  }
}

const finalNicheColor = nicheColors[detectedNiche] || '#6366f1';
const brandName = domainRoot.charAt(0).toUpperCase() + domainRoot.slice(1);

return [{
  json: {
    rawUrl,
    cleanUrl,
    domain,
    domainRoot,
    tld,
    slug,
    brandName,
    name,
    email,
    niche,
    detectedNiche,
    nicheColor: finalNicheColor,
    strategy,
    config,
    region,
    timestamp: new Date().toISOString(),
    reportId: 'BL-' + Date.now()
  }
}];

// ============================================================
// PARSE SCRAPED HTML — Extract title, meta, keywords
// Reads data from Validate node (not scrape, which may fail)
// ============================================================

// Get validated data from the Validate node
const validated = $('Validate URL and Detect Niche').first().json;

// Get scraped HTML (may be empty string or object if scrape failed)
let html = '';
try {
  const scrapeResult = $input.first().json;
  if (typeof scrapeResult === 'string') {
    html = scrapeResult;
  } else if (scrapeResult && typeof scrapeResult.data === 'string') {
    html = scrapeResult.data;
  } else {
    html = JSON.stringify(scrapeResult || '');
  }
} catch(e) {
  html = '';
}

// --- Extract page title ---
let siteTitle = validated.brandName;
try {
  const tm = html.match(/<title[^>]*>([^<]{1,120})<\/title>/i);
  if (tm && tm[1]) siteTitle = tm[1].trim().replace(/\s+/g, ' ');
} catch(e) {}

// --- Extract meta description ---
let metaDesc = validated.brandName + ' is a ' + validated.detectedNiche + ' website.';
try {
  const mm = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']{10,250})["']/i)
           || html.match(/<meta[^>]+content=["']([^"']{10,250})["'][^>]+name=["']description["']/i);
  if (mm && mm[1]) metaDesc = mm[1].trim();
} catch(e) {}

// --- Extract keywords from page text ---
const stopWords = ['the','and','for','that','this','with','from','your','are','was','has','have','not','but','can','all','any','been','they','their','will','would','could','should','about','which','when','what','how','just','more','also','into','than','its','use','used','using','you','our','we','be','is','in','on','at','to','a','of','it','do','so','as','by','or','an','if','up','out','no','he','she','his','her'];
let topKeywords = [];
try {
  const text = html.replace(/<[^>]+>/g, ' ').toLowerCase();
  const wordMatches = text.match(/\b[a-z]{4,18}\b/g) || [];
  const freq = {};
  for (let i = 0; i < wordMatches.length; i++) {
    const w = wordMatches[i];
    if (stopWords.indexOf(w) === -1) {
      freq[w] = (freq[w] || 0) + 1;
    }
  }
  topKeywords = Object.keys(freq)
    .sort(function(a,b){ return freq[b] - freq[a]; })
    .slice(0, 15);
} catch(e) {}

// Fallback keywords by niche
const nicheKeywords = {
  'Technology & Software':  ['software','platform','tools','automation','integration','cloud','developer','API','solution','technology'],
  'E-commerce & Retail':    ['products','shop','deals','collection','shipping','checkout','brand','store','fashion','sale'],
