  'Food & Restaurant':      ['food','recipes','restaurant','cuisine','menu','delivery','dining','ingredients','cooking','chef'],
  'Real Estate':            ['property','homes','listing','mortgage','investment','neighborhood','apartment','realty','buy','rent'],
  'Marketing & SEO':        ['SEO','content','branding','campaigns','traffic','leads','analytics','social','conversion','strategy'],
  'Legal & Law':            ['legal','attorney','law','counsel','rights','compliance','litigation','firm','contracts','advice'],
