  'Business & Services':    ['business','services','solutions','professional','quality','reliable','expert','consulting','agency','team']
};

if (topKeywords.length < 5) {
  topKeywords = nicheKeywords[validated.detectedNiche] || nicheKeywords['Business & Services'];
}

return [{
